            if (updateItemLineRequest.LotNumberOption.IsSet)
                if (updateItemLineRequest.LotNumberOption.Value != null)
                    writer.WriteString("lotNumber", updateItemLineRequest.LotNumber);
                else
                    writer.WriteNull("lotNumber");

            if (updateItemLineRequest.ExpirationDateForSerialLotNumberOption.IsSet)
                if (updateItemLineRequest.ExpirationDateForSerialLotNumberOption.Value != null)
                    writer.WriteString("expirationDateForSerialLotNumber", updateItemLineRequest.ExpirationDateForSerialLotNumber);
                else
                    writer.WriteNull("expirationDateForSerialLotNumber");

            if (updateItemLineRequest.OverrideItemAccountIdOption.IsSet)
                if (updateItemLineRequest.OverrideItemAccountIdOption.Value != null)
                    writer.WriteString("overrideItemAccountId", updateItemLineRequest.OverrideItemAccountId);
                else
                    writer.WriteNull("overrideItemAccountId");

            if (updateItemLineRequest.SalesRepresentativeIdOption.IsSet)
                if (updateItemLineRequest.SalesRepresentativeIdOption.Value != null)
                    writer.WriteString("salesRepresentativeId", updateItemLineRequest.SalesRepresentativeId);
                else
                    writer.WriteNull("salesRepresentativeId");
        }
    }
}
